/** Auto-generated from Downloads/홈 named assets — Granite `{ uri }`. */
export const HOME_DECOR_IMAGE_URI = {
    home_hero: 'data:image/png;base64,',
    stamp_pending: 'data:image/png;base64,',
    stamp_progress: 'data:image/png;base64,',
    stamp_done: 'data:image/png;base64,',
    progress_wait: 'data:image/png;base64,',
    progress_mid: 'data:image/png;base64,',
    progress_excited: 'data:image/png;base64,',
    banner_veggies: 'data:image/png;base64,',
    bg_pattern: 'data:image/png;base64,',
    deco_sparkle: 'data:image/png;base64,',
} as const;

export type HomeDecorImageUriKey = keyof typeof HOME_DECOR_IMAGE_URI;

export function homeDecorUriSource(key: HomeDecorImageUriKey): { uri: string } {
    return { uri: HOME_DECOR_IMAGE_URI[key] };
}
